import java.util.Scanner;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input by escaping special characters
        String sanitizedInput = escapeHtml(userInput);

        // Display the greeting message with sanitized input
        String greetingMessage = "Hello, " + sanitizedInput + "! Welcome to our website!";

        // Display the sanitized greeting message
        System.out.println(greetingMessage);
    }

    // Method to escape HTML special characters in user input
    private static String escapeHtml(String input) {
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
